//
// Package parsunart is the runtime shared by every Go parser generated by
// parsuna.
//
// A generated grammar package supplies its own TokenKind / RuleKind types
// (as uint16 aliases), a MatcherFunc, a skip-kind predicate, and a Step
// callback that runs one state body of the dispatch. Everything else —
// lexing, lookahead, skip routing, error recovery — lives here.
package parsunart

import (
	"fmt"
	"io"
	"unicode/utf8"
)

// Pos is a source position: byte offset plus 1-based line/column.
type Pos struct {
	Offset uint32
	Line   uint32
	Column uint32
}

// Span is a half-open range [Start, End) over the source.
type Span struct {
	Start, End Pos
}

// PointSpan is a zero-width span at a single point.
func PointSpan(p Pos) Span { return Span{Start: p, End: p} }

// Token is a lexed token: kind, source span, and the matched text.
//
// Kind is stored as uint16 to match the generated TokenKind enum's values.
// EOF is always 0 (EofKind); grammar tokens have ids starting at 1; the
// lexer emits ErrorKind (0xFFFF) when no DFA pattern matched at the
// current position.
type Token struct {
	Kind uint16
	Span Span
	Text string
}

// EofKind is the token-kind id reserved for end-of-input. Always 0.
const EofKind uint16 = 0

// ErrorKind is the token-kind sentinel emitted when the lexer can't match
// any pattern at the current position. Distinct from any grammar token id
// (0..0xFFFE), so dispatch arms naturally fall through to the recovery
// path.
const ErrorKind uint16 = 0xFFFF

// ParseError is a recoverable parse or lex error with its source span.
type ParseError struct {
	Message string
	Span    Span
}

// String formats the error as `error[line:col]: message`.
func (d ParseError) String() string {
	s, e := d.Span.Start, d.Span.End
	if s == e {
		return fmt.Sprintf("error[%d:%d]: %s", s.Line, s.Column, d.Message)
	}
	return fmt.Sprintf("error[%d:%d-%d:%d]: %s", s.Line, s.Column, e.Line, e.Column, d.Message)
}

// EventTag discriminates Event payload fields.
type EventTag uint8

const (
	EvEnter EventTag = iota
	EvExit
	EvToken
	// EvGarbage is a token consumed during error recovery — emitted
	// between an EvError and the recovery's sync point. Distinct from
	// EvToken so consumers can drop these from their AST or render
	// them as error spans without tracking recovery state externally.
	EvGarbage
	EvError
)

// Event is a single pull-parser event. Tag is one of the EV_* constants;
// the matching payload field (Rule, Token, Err) carries the data.
type Event struct {
	Tag   EventTag
	Rule  uint16
	Pos   Pos
	Token Token
	Err   ParseError
}

// Terminated is the sentinel state that means "parser finished".
const Terminated = -1

// MatcherFunc is the grammar-specific compiled DFA the runtime drives.
// It scans buf[start:] for the longest matching token. Returns
// (bestLen, bestKind, scanned):
//   - bestLen: bytes consumed by the longest match (0 means no accept).
//   - bestKind: token kind of the longest match, or ErrorKind when no
//     accept state was reached.
//   - scanned: total bytes walked past start; equals len(buf)-start when
//     the scan stopped at end of input rather than a dead transition. The
//     streaming lexer uses this to detect buffer exhaustion mid-token.
type MatcherFunc func(buf []byte, start int) (int, uint16, int)

const lexChunk = 16384

// Lexer is a streaming DFA-driven lexer over an io.Reader. The grammar-
// specific DFA is supplied as a MatcherFunc.
type Lexer struct {
	reader    io.Reader
	buf       []byte
	bufPos    int
	eof       bool
	offset    uint32
	line, col uint32
	matcher   MatcherFunc
}

// NewLexer builds a lexer over r.
func NewLexer(r io.Reader, matcher MatcherFunc) *Lexer {
	return &Lexer{reader: r, line: 1, col: 1, matcher: matcher}
}

func (l *Lexer) pos() Pos { return Pos{Offset: l.offset, Line: l.line, Column: l.col} }

func (l *Lexer) readMore() bool {
	if l.eof {
		return false
	}
	if cap(l.buf)-len(l.buf) < lexChunk {
		newCap := cap(l.buf) * 2
		if newCap < len(l.buf)+lexChunk {
			newCap = len(l.buf) + lexChunk*2
		}
		nb := make([]byte, len(l.buf), newCap)
		copy(nb, l.buf)
		l.buf = nb
	}
	n, err := l.reader.Read(l.buf[len(l.buf) : len(l.buf)+lexChunk])
	if n > 0 {
		l.buf = l.buf[:len(l.buf)+n]
	}
	if err != nil || n == 0 {
		l.eof = true
		return n > 0
	}
	return true
}

func (l *Lexer) ensure(want int) {
	for !l.eof && len(l.buf)-l.bufPos < want {
		if !l.readMore() {
			break
		}
	}
}

// advance bumps position. Fast-path for pure ASCII non-newline slices,
// byte-by-byte walk otherwise so lines/columns track multi-byte UTF-8.
func (l *Lexer) advance(n int) {
	end := l.bufPos + n

	needsWalk := false
	for i := l.bufPos; i < end; i++ {
		b := l.buf[i]
		if b == '\n' || b >= 0x80 {
			needsWalk = true
			break
		}
	}
	if !needsWalk {
		l.col += uint32(n)
		l.offset += uint32(n)
		l.bufPos = end
	} else {
		for l.bufPos < end {
			b := l.buf[l.bufPos]
			l.bufPos++
			l.offset++
			if b == '\n' {
				l.line++
				l.col = 1
			} else if (b & 0xC0) != 0x80 {
				l.col++
			}
		}
	}
	if l.bufPos > 65536 {
		copy(l.buf, l.buf[l.bufPos:])
		l.buf = l.buf[:len(l.buf)-l.bufPos]
		l.bufPos = 0
	}
}

func (l *Lexer) longestMatch() (int, uint16) {
	for {
		bestLen, bestKind, scanned := l.matcher(l.buf, l.bufPos)
		viewLen := len(l.buf) - l.bufPos
		if !l.eof && scanned == viewLen {
			if l.readMore() {
				continue
			}
		}
		return bestLen, bestKind
	}
}

// NextToken produces the next token. Emits repeated EOF once input ends.
// Lex failures come through with Kind == ErrorKind (0xFFFF).
func (l *Lexer) NextToken() Token {
	l.ensure(lexChunk)
	if len(l.buf)-l.bufPos == 0 {
		p := l.pos()
		return Token{Kind: EofKind, Span: PointSpan(p)}
	}
	bestLen, bestKind := l.longestMatch()
	start := l.pos()
	if bestLen == 0 {
		_, n := utf8.DecodeRune(l.buf[l.bufPos:])
		if n < 1 {
			n = 1
		}
		text := string(l.buf[l.bufPos : l.bufPos+n])
		l.advance(n)
		return Token{Kind: ErrorKind, Span: Span{Start: start, End: l.pos()}, Text: text}
	}
	text := string(l.buf[l.bufPos : l.bufPos+bestLen])
	l.advance(bestLen)
	return Token{Kind: bestKind, Span: Span{Start: start, End: l.pos()}, Text: text}
}

// Config is the grammar-specific callback bundle a generated parser wires
// into the runtime.
type Config struct {
	K      int
	IsSkip func(kind uint16) bool
	// Step runs one state body of the generated dispatch. Returns
	// the event that body produced (with `ok = true`) or a zero
	// Event and `ok = false` if the body was a pure transition step
	// — the runtime's NextEvent loop calls Step again in that case.
	Step func(p *Parser) (Event, bool)
}

// recovery is in-flight error recovery. Set by TryConsume's mismatch
// path and RecoverTo; cleared once the lookahead lands on a sync token
// (or EOF). Each call to NextEvent in recovery mode yields one Garbage
// event before re-checking the sync set.
type recovery struct {
	// sync is the set of token kinds to recover *to*. Recovery
	// consumes garbage until the lookahead matches one of these (or
	// EOF).
	sync []uint16
	// expected is set when recovery was triggered by a TryConsume for
	// a specific kind. expectedSet distinguishes "no expected kind"
	// from "expected kind 0 (EOF)".
	expected    uint16
	expectedSet bool
}

// Parser is the pull-based parser. Obtain one via NewParser, then call
// NextEvent in a loop.
//
// Each NextEvent call fires one of three modes — pump (refill lookahead,
// possibly yielding a skip), recovery (one Garbage / synced-Token event
// per call), or drive (one Step call) — and yields one event per mode.
// Step may return ok=false for pure-transition state bodies; the runtime
// simply loops drive again.
type Parser struct {
	lex *Lexer
	// look is the lookahead ring, length K. Empty slots are awaiting
	// refill via pump-mode in NextEvent. Empty slots are always a
	// contiguous suffix — Consume parks the new empty slot at index
	// K-1 and pump fills the leftmost empty.
	look       []Token
	lookFilled []bool
	prevEnd    Pos
	state      int
	ret        []int
	rec        recovery
	recActive  bool
	eofChecked bool
	cfg        Config
}

// NewParser builds a parser starting at state `entry`.
//
// All K lookahead slots start empty; the first call to NextEvent enters
// pump-mode and primes them, so any leading skip tokens (e.g. whitespace
// before the first structural token) are emitted before the entry rule's
// Enter event.
func NewParser(lex *Lexer, entry int, cfg Config) *Parser {
	return &Parser{
		lex:        lex,
		state:      entry,
		cfg:        cfg,
		look:       make([]Token, cfg.K),
		lookFilled: make([]bool, cfg.K),
	}
}

// Look peeks at the i-th lookahead token. Generated Step only runs
// after pump-mode has filled every slot, so callers can read any slot
// unconditionally.
func (p *Parser) Look(i int) Token { return p.look[i] }

// State returns the current state id.
func (p *Parser) State() int { return p.state }

// SetState overwrites the current state id.
func (p *Parser) SetState(s int) { p.state = s }

// PushRet pushes a return address onto the call stack.
func (p *Parser) PushRet(s int) { p.ret = append(p.ret, s) }

// PopRet pops the top return address, or Terminated when the stack is empty.
func (p *Parser) PopRet() int {
	if len(p.ret) == 0 {
		return Terminated
	}
	s := p.ret[len(p.ret)-1]
	p.ret = p.ret[:len(p.ret)-1]
	return s
}

// MatchesFirst reports whether the current lookahead matches any prefix
// in set. Used by generated dispatch logic with k > 1 lookahead.
func (p *Parser) MatchesFirst(set [][]uint16) bool {
outer:
	for _, seq := range set {
		for i, want := range seq {
			if p.look[i].Kind != want {
				continue outer
			}
		}
		return true
	}
	return false
}

func containsKind(set []uint16, k uint16) bool {
	for _, x := range set {
		if x == k {
			return true
		}
	}
	return false
}

// Enter builds an Enter event for `rule` and returns it. Records the
// rule's start position as prevEnd so a later Exit without any
// intervening tokens still produces a zero-width span at the expected
// place.
func (p *Parser) Enter(rule uint16) Event {
	pos := p.look[0].Span.Start
	p.prevEnd = pos
	return Event{Tag: EvEnter, Rule: rule, Pos: pos}
}

// Exit builds an Exit event for `rule`, anchored at the end of the
// previously consumed token (or the rule's start for empty rules).
func (p *Parser) Exit(rule uint16) Event {
	return Event{Tag: EvExit, Rule: rule, Pos: p.prevEnd}
}

// takeToken pops the current lookahead token and shifts the buffer up
// by one. Slot K-1 is left empty so pump-mode can refill it before the
// next Step reads lookahead. Internal — callers wrap the result in
// the appropriate event tag.
func (p *Parser) takeToken() Token {
	t := p.look[0]
	p.prevEnd = t.Span.End
	for i := 0; i < p.cfg.K-1; i++ {
		p.look[i] = p.look[i+1]
		p.lookFilled[i] = p.lookFilled[i+1]
	}
	p.look[p.cfg.K-1] = Token{}
	p.lookFilled[p.cfg.K-1] = false
	return t
}

// Consume consumes the current lookahead and returns it as a Token
// event. Used on TryConsume's success path and on recovery's
// "synced-to-expected" path — both yield legitimate parse data.
func (p *Parser) Consume() Event {
	return Event{Tag: EvToken, Token: p.takeToken()}
}

// TryConsume tries to consume a token of `kind`. On a hit returns a
// Token event. On a miss returns an Error event and arms recovery —
// subsequent NextEvent calls skip Garbage one token at a time until
// the lookahead lands on `sync` (when it does, the matching token
// comes through as a normal Token event).
func (p *Parser) TryConsume(kind uint16, sync []uint16, name string) Event {
	if p.look[0].Kind == kind {
		return p.Consume()
	}
	ev := p.ErrorHere("expected " + name)
	p.rec = recovery{sync: sync, expected: kind, expectedSet: true}
	p.recActive = true
	return ev
}

// RecoverTo arms recovery without an expected kind. Called from the
// dispatch error leaf: the caller has already arranged the
// post-recovery state and the returned Error event makes Step yield
// so recovery-mode can take over.
func (p *Parser) RecoverTo(sync []uint16) {
	p.rec = recovery{sync: sync, expectedSet: false}
	p.recActive = true
}

// ErrorHere returns a recoverable error event at the current lookahead.
func (p *Parser) ErrorHere(msg string) Event {
	return Event{Tag: EvError, Err: ParseError{Message: msg, Span: p.look[0].Span}}
}

// NextEvent returns the next parse event and true, or a zero Event and
// false once input is fully consumed.
//
// The loop runs three modes — pump, recovery, drive — each yielding at
// most one event per iteration before the loop runs again.
func (p *Parser) NextEvent() (Event, bool) {
	for {
		// Skip mode: refill any empty lookahead slot. Slots fill
		// leftmost-first and Consume parks new empties at K-1, so
		// checking slot K-1 is the O(1) form of "any slot empty".
		if !p.lookFilled[p.cfg.K-1] {
			t := p.lex.NextToken()
			if p.cfg.IsSkip(t.Kind) {
				return Event{Tag: EvToken, Token: t}, true
			}
			for i, ok := range p.lookFilled {
				if !ok {
					p.look[i] = t
					p.lookFilled[i] = true
					break
				}
			}
			continue
		}

		// Recovery mode: advance one step. Yield a Garbage event
		// for an unexpected token, a Token event when the sync hit
		// on the kind we were expecting, or finalise without
		// consuming and loop.
		if p.recActive {
			k := p.look[0].Kind
			synced := k == EofKind || containsKind(p.rec.sync, k)
			if synced {
				wasExpected := p.rec.expectedSet && p.rec.expected == k
				p.recActive = false
				if wasExpected {
					return p.Consume(), true
				}
				continue
			}
			return Event{Tag: EvGarbage, Token: p.takeToken()}, true
		}

		// EOF gate at Terminated. If trailing input remains, raise
		// an error and arm an empty-sync recovery so the rest of
		// the input drains as Garbage events one per call.
		if p.state == Terminated {
			if !p.eofChecked {
				p.eofChecked = true
				if p.look[0].Kind != EofKind {
					ev := p.ErrorHere("expected end of input")
					p.rec = recovery{sync: nil, expectedSet: false}
					p.recActive = true
					return ev, true
				}
				continue
			}
			return Event{}, false
		}

		// Drive mode: run one state body. If Step emitted, yield
		// it. Otherwise it just transitioned `cur` (and possibly
		// the return stack); loop and run the next body.
		if ev, ok := p.cfg.Step(p); ok {
			return ev, true
		}
	}
}
